// PressPilot Factory - Transform Input
// Maps frontend form fields to Factory API format

const input = items[0].json;

// Map frontend businessType/industry to Factory API category
const categoryMap = {
  'Restaurant / Food Service': 'restaurant',
  'Real Estate / Architecture': 'realestate',
  'Tech / SaaS': 'startup',
  'Health / Wellness': 'fitness',
  'Creative Agency': 'agency',
  'E-commerce': 'ecommerce',
  'Personal Portfolio': 'corporate'
};

// Handle various field name formats from proxy
const businessName = input.business_name || input.businessName || 'My Business';
const businessType = input.industry || input.businessType || 'corporate';
const category = categoryMap[businessType] || 'corporate';

// Build Factory API payload
return [{
  json: {
    businessName: businessName,
    tagline: input.tagline || '',
    description: input.description || '',
    category: category,
    colors: {
      primary: '#1e40af',
      secondary: '#64748b',
      accent: '#f59e0b',
      background: '#ffffff',
      text: '#1f2937'
    },
    logo: input.logo_base64 || input.logo || null
  }
}];
